// ============================================
// PREPARE STORY CONTEXT FOR SCRIPT GENERATION
// Merges selected story + character details + series config
// Output goes to Node 2 (Ollama Script Generation)
// ============================================

const data = $input.first().json;
const story = data.selectedStory;
const characters = data.characterDetails;
const series = data.seriesConfig;

// Build character descriptions for the LLM prompt
const characterDescriptions = Object.entries(characters || {}).map(([id, char]) => {
  return `- ${char.name}: ${char.personality}. Catchphrase: "${char.catchphrase}". Voice: ${char.voiceId}`;
}).join('\n');

// Count episode number
const episodeNumber = (series.episodeCount || 0) + 1;

return [{
  json: {
    // Story details
    storyTitle: story.title,
    storyPremise: story.premise,
    storyGenre: story.genre,
    storyThemes: story.themes || [],
    storyMood: story.mood || 'exciting',
    storySource: story.source,
    storyScore: story.score,

    // Character info (for LLM prompt)
    characters: characters,
    characterDescriptions: characterDescriptions,
    characterIds: story.characters || [],

    // Series info
    seriesName: series.name || 'Finn, Squeaky & Misty Adventures',
    seriesStyle: series.style || '2d cartoon, anime cel shading, clean lineart, flat colors, vibrant palette',
    seriesGenre: series.genre || 'adventure',
    checkpoint: series.checkpoint || '',
    negativePrompt: series.negativePrompt || '',
    episodeNumber: episodeNumber,

    // Rankings (for debugging)
    rankedIdeas: data.rankedIdeas || [],
    totalScored: data.totalScored || 0,

    // Timestamps
    pickedAt: data.pickedAt,
    pipelineStartedAt: new Date().toISOString()
  }
}];

// ============================================
// STRUCTURE SCRIPT OUTPUT
// Validate script, merge with pipeline context
// Prepare data for Node 3 (Scene Planner)
// ============================================

const prevData = $('Prepare Story Context').first().json;
const result = $input.first().json;
const script = result.script;

// Merge scene data with character visual prompts
const characters = prevData.characters || {};
const scenes = (script.scenes || []).map((scene, i) => {
  // Enrich each scene with character prompt data for image generation
  const sceneChars = {};
  for (const cid of (scene.charactersInScene || [])) {
    if (characters[cid]) {
      sceneChars[cid] = {
        name: characters[cid].name,
        prompt: characters[cid].prompt,
        loraFile: characters[cid].loraFile || '',
        loraWeight: characters[cid].loraWeight || 0.8,
        voiceId: characters[cid].voiceId || 'en-US-DavisNeural',
        ipAdapterRef: characters[cid].ipAdapterRef || ''
      };
    }
  }
  return {
    ...scene,
    sceneNumber: i + 1,
    characterPrompts: sceneChars
  };
});

return [{
  json: {
    // Script data
    title: script.title,
    description: script.description,
    tags: script.tags || [],
    scenes: scenes,
    fullNarration: script.fullNarration,
    thumbnailDescription: script.thumbnailDescription || '',
    cliffhanger: script.cliffhanger || '',
    totalScenes: scenes.length,
    estimatedDuration: script.estimatedDuration || 0,

    // LLM metadata
    llmProvider: result.provider,
    promptLength: result.prompt_length,
    responseLength: result.response_length,
    llmErrors: result.errors || [],

    // Pipeline context (pass through)
    seriesName: prevData.seriesName,
    seriesStyle: prevData.seriesStyle,
    checkpoint: prevData.checkpoint,
    negativePrompt: prevData.negativePrompt,
    episodeNumber: prevData.episodeNumber,
    storyTitle: prevData.storyTitle,
    storySource: prevData.storySource,
    characters: prevData.characters,
    characterIds: prevData.characterIds,

    // Timestamps
    pipelineStartedAt: prevData.pipelineStartedAt,
    scriptGeneratedAt: new Date().toISOString()
  }
}];

// ============================================
// COLLECT SCENE PLAN & PREPARE FOR GENERATION
// Split into image tasks, animation tasks, audio tasks
// This is the last planning node before actual generation
// ============================================

const plan = $input.first().json;
const prevData = $('Structure Script Output').first().json;

// Extract all image tasks for batch processing
const imageTasks = plan.scenes.map(s => s.imageTask);

// Extract all animation tasks
const animationTasks = plan.scenes.map(s => s.animationTask);

// Extract all audio tasks (flatten per-scene arrays)
const audioTasksFlat = [];
for (const scene of plan.scenes) {
  for (const task of (scene.audioTasks || [])) {
    audioTasksFlat.push({
      ...task,
      sceneNumber: scene.sceneNumber
    });
  }
}

// Build scene summaries for logging
const sceneSummaries = plan.scenes.map(s => ({
  scene: s.sceneNumber,
  duration: s.duration + 's',
  emotion: s.emotion,
  camera: s.cameraAngle,
  characters: s.charactersInScene.length,
  audioFiles: s.audioTasks.length,
  hasLoRA: s.imageTask.loras.length > 0
}));

return [{
  json: {
    // Generation task lists
    imageTasks: imageTasks,
    animationTasks: animationTasks,
    audioTasks: audioTasksFlat,
    thumbnailTask: plan.thumbnailTask,
    manualImageGuide: plan.manualImageGuide || {},
    fullNarrationTask: plan.fullNarrationTask,

    // Scene plan (full detail for assembly node later)
    scenes: plan.scenes,

    // Metadata
    metadata: plan.metadata,
    settings: plan.settings,
    directories: plan.directories,

    // Stats
    totalScenes: plan.totalScenes,
    estimatedDuration: plan.estimatedDuration,
    totalImageTasks: imageTasks.length,
    totalAnimationTasks: animationTasks.length,
    totalAudioTasks: audioTasksFlat.length,
    hasLoRAs: plan.hasLoRAs,
    sceneSummaries: sceneSummaries,

    // Pipeline tracking
    pipelineStartedAt: prevData.pipelineStartedAt,
    scriptGeneratedAt: prevData.scriptGeneratedAt,
    scenesPlannedAt: new Date().toISOString()
  }
}];

// ============================================
// COLLECT VISUAL RESULTS
// Map generated images + clips back to scenes
// Prepare data for Node 5 (Audio Generation)
// ============================================

const visuals = $input.first().json;
const planData = $('Collect Scene Plan').first().json;

if (!visuals.success) {
  throw new Error('Visual generation failed: ' + JSON.stringify(visuals));
}

// Build per-scene visual result map
const imageMap = {};
for (const img of (visuals.images || [])) {
  imageMap[img.scene] = img;
}
const clipMap = {};
for (const clip of (visuals.clips || [])) {
  clipMap[clip.scene] = clip;
}

// Enrich scenes with visual generation results
const enrichedScenes = (planData.scenes || []).map((scene, i) => {
  const sn = scene.sceneNumber || (i + 1);
  const img = imageMap[sn] || {};
  const clip = clipMap[sn] || {};
  return {
    ...scene,
    imageResult: {
      success: img.success || false,
      path: img.path || '',
      filename: img.filename || '',
      method: img.method || 'none',
      error: img.error || ''
    },
    clipResult: {
      success: clip.success || false,
      path: clip.path || '',
      filename: clip.filename || '',
      method: clip.method || 'none',
      secondKeyframePath: clip.secondKeyframePath || '',
      error: clip.error || ''
    }
  };
});

// Count successes
const imgOk = enrichedScenes.filter(s => s.imageResult.success).length;
const clipOk = enrichedScenes.filter(s => s.clipResult.success).length;
const adClips = enrichedScenes.filter(s => s.clipResult.method === 'animatediff').length;
const kbClips = enrichedScenes.filter(s => s.clipResult.method === 'ken_burns').length;

if (imgOk !== enrichedScenes.length || clipOk !== enrichedScenes.length) {
  throw new Error(`Visual generation incomplete: ${imgOk}/${enrichedScenes.length} images, ${clipOk}/${enrichedScenes.length} clips`);
}

return [{
  json: {
    // Enriched scenes with visual paths
    scenes: enrichedScenes,

    // Audio tasks (unchanged, for Node 5)
    audioTasks: planData.audioTasks,
    fullNarrationTask: planData.fullNarrationTask,

    // Thumbnail
    thumbnail: visuals.thumbnail || null,

    // Metadata (pass through)
    metadata: planData.metadata,
    settings: planData.settings,
    directories: planData.directories,

    // Visual generation stats
    visualStats: {
      totalScenes: enrichedScenes.length,
      imagesGenerated: imgOk,
      clipsGenerated: clipOk,
      animatediffClips: adClips,
      kenBurnsClips: kbClips,
      elapsedSeconds: visuals.elapsedSeconds || 0,
      hasAnimateDiff: visuals.hasAnimateDiff || false,
      pollinationsImages: visuals.pollinationsImages || 0,
      primaryGenerator: visuals.primaryGenerator || 'unknown'
    },

    // Pipeline tracking
    pipelineStartedAt: planData.pipelineStartedAt,
    scriptGeneratedAt: planData.scriptGeneratedAt,
    scenesPlannedAt: planData.scenesPlannedAt,
    visualsGeneratedAt: new Date().toISOString()
  }
}];

// ============================================
// COLLECT AUDIO RESULTS
// Map audio paths + subtitles + durations back to scenes
// Prepare sync data for Node 6 (Video Assembly)
// ============================================

const audio = $input.first().json;
const prevData = $('Collect Visual Results').first().json;

// Build audio result map by scene number
const audioMap = {};
for (const scene of (audio.scenes || [])) {
  audioMap[scene.sceneNumber] = scene;
}

// Enrich scenes with audio + subtitle paths and ACTUAL durations
const enrichedScenes = (prevData.scenes || []).map((scene, i) => {
  const sn = scene.sceneNumber || (i + 1);
  const audioResult = audioMap[sn] || {};
  return {
    ...scene,
    audioResult: {
      success: audioResult.success || false,
      combinedAudioPath: audioResult.combinedAudioPath || '',
      combinedAudioFilename: audioResult.combinedAudioFilename || '',
      duration: audioResult.duration || 0,
      subtitlePath: audioResult.subtitlePath || '',
      subtitleFilename: audioResult.subtitleFilename || '',
      segments: audioResult.segments || [],
      wordTimestamps: audioResult.wordTimestamps || []
    }
  };
});

// Build sync map: sceneNumber -> actual audio duration
// Node 6 uses this to stretch/trim video clips to match audio exactly
const syncMap = {};
for (const s of enrichedScenes) {
  if (s.audioResult.success) {
    syncMap[s.sceneNumber] = {
      audioDuration: s.audioResult.duration,
      clipPath: s.clipResult ? s.clipResult.path : '',
      audioPath: s.audioResult.combinedAudioPath,
      subtitlePath: s.audioResult.subtitlePath
    };
  }
}

const audioOk = enrichedScenes.filter(s => s.audioResult.success).length;

return [{
  json: {
    // Fully enriched scenes (visual + audio + subtitles)
    scenes: enrichedScenes,

    // Sync data for Node 6 assembly
    syncMap: syncMap,
    totalAudioDuration: audio.totalDuration || 0,

    // Full video subtitle
    fullVideoSubtitle: audio.fullVideoSubtitle || {},
    fullNarration: audio.fullNarration || null,

    // Thumbnail (pass through)
    thumbnail: prevData.thumbnail || null,

    // Metadata (pass through)
    metadata: prevData.metadata,
    settings: prevData.settings,
    directories: prevData.directories,

    // Stats
    audioStats: {
      totalScenes: audio.totalScenes || 0,
      scenesGenerated: audioOk,
      totalDuration: audio.totalDuration || 0,
      rate: audio.rate || '+0%',
      narratorVoice: audio.narratorVoice || 'en-US-DavisNeural',
      elapsedSeconds: audio.elapsedSeconds || 0
    },
    visualStats: prevData.visualStats || {},

    // Pipeline tracking
    pipelineStartedAt: prevData.pipelineStartedAt,
    scriptGeneratedAt: prevData.scriptGeneratedAt,
    scenesPlannedAt: prevData.scenesPlannedAt,
    visualsGeneratedAt: prevData.visualsGeneratedAt,
    audioGeneratedAt: new Date().toISOString()
  }
}];

// ============================================
// COLLECT ASSEMBLY RESULTS
// Package final video info for upload/SEO nodes
// ============================================

const assembly = $input.first().json;
const prevData = $('Collect Audio Results').first().json;

return [{
  json: {
    // Final video
    videoPath: assembly.outputPath || '',
    videoFilename: assembly.outputFilename || '',
    videoDuration: assembly.duration || 0,
    videoFileSize: assembly.fileSize || 0,
    videoFileSizeMB: assembly.fileSizeMB || 0,
    resolution: assembly.resolution || '1080x1920',
    subtitlesBurned: assembly.subtitlesBurned || false,

    // Thumbnail (from Node 4)
    thumbnail: prevData.thumbnail || null,

    // Metadata for upload
    metadata: prevData.metadata || {},

    // Assembly stats
    assemblyStats: {
      scenesAssembled: assembly.scenesAssembled || 0,
      totalScenes: assembly.totalScenes || 0,
      elapsedSeconds: assembly.elapsedSeconds || 0,
      clipDetails: assembly.clipDetails || []
    },
    visualStats: prevData.visualStats || {},
    audioStats: prevData.audioStats || {},

    // Pipeline tracking
    pipelineStartedAt: prevData.pipelineStartedAt,
    scriptGeneratedAt: prevData.scriptGeneratedAt,
    scenesPlannedAt: prevData.scenesPlannedAt,
    visualsGeneratedAt: prevData.visualsGeneratedAt,
    audioGeneratedAt: prevData.audioGeneratedAt,
    videoAssembledAt: new Date().toISOString()
  }
}];

// ============================================
// COLLECT SEO RESULTS
// Package SEO metadata for thumbnail + upload nodes
// ============================================

const seoResp = $input.first().json;
const prevData = $('Collect Assembly Results').first().json;

const seo = seoResp.seo || {};

return [{
  json: {
    // SEO metadata
    youtubeTitle: seo.title || prevData.metadata?.storyTitle || 'Untitled Episode',
    youtubeDescription: seo.description || '',
    youtubeTags: seo.tags || [],
    youtubeCategory: seo.category || 'Film & Animation',
    shortDescription: seo.shortDescription || '',
    chapterTimestamps: seo.chapterTimestamps || '',
    seoProvider: seoResp.provider || 'unknown',

    // Pass through video info
    videoPath: prevData.videoPath,
    videoFilename: prevData.videoFilename,
    videoDuration: prevData.videoDuration,
    videoFileSize: prevData.videoFileSize,
    videoFileSizeMB: prevData.videoFileSizeMB,
    resolution: prevData.resolution,
    subtitlesBurned: prevData.subtitlesBurned,

    // Pass through thumbnail
    thumbnail: prevData.thumbnail,

    // Pass through metadata
    metadata: prevData.metadata,

    // Stats
    assemblyStats: prevData.assemblyStats,
    visualStats: prevData.visualStats,
    audioStats: prevData.audioStats,

    // Pipeline tracking
    pipelineStartedAt: prevData.pipelineStartedAt,
    scriptGeneratedAt: prevData.scriptGeneratedAt,
    scenesPlannedAt: prevData.scenesPlannedAt,
    visualsGeneratedAt: prevData.visualsGeneratedAt,
    audioGeneratedAt: prevData.audioGeneratedAt,
    videoAssembledAt: prevData.videoAssembledAt,
    seoGeneratedAt: new Date().toISOString()
  }
}];

// ============================================
// COLLECT THUMBNAIL RESULTS
// Package thumbnail + all pipeline data for upload
// ============================================

const thumbResp = $input.first().json;
const prevData = $('Collect SEO Results').first().json;

return [{
  json: {
    // Thumbnail
    thumbnailPath: thumbResp.path || '',
    thumbnailJpegPath: thumbResp.jpegPath || '',
    thumbnailFilename: thumbResp.filename || 'thumbnail_final.png',
    thumbnailResolution: thumbResp.resolution || '1280x720',
    thumbnailUsedFallback: thumbResp.usedFallbackBackground || false,

    // SEO (from Node 7)
    youtubeTitle: prevData.youtubeTitle,
    youtubeDescription: prevData.youtubeDescription,
    youtubeTags: prevData.youtubeTags,
    youtubeCategory: prevData.youtubeCategory,
    shortDescription: prevData.shortDescription,
    chapterTimestamps: prevData.chapterTimestamps,

    // Video (from Node 6)
    videoPath: prevData.videoPath,
    videoFilename: prevData.videoFilename,
    videoDuration: prevData.videoDuration,
    videoFileSize: prevData.videoFileSize,
    videoFileSizeMB: prevData.videoFileSizeMB,
    resolution: prevData.resolution,

    // Metadata
    metadata: prevData.metadata,

    // Pipeline tracking
    pipelineStartedAt: prevData.pipelineStartedAt,
    scriptGeneratedAt: prevData.scriptGeneratedAt,
    scenesPlannedAt: prevData.scenesPlannedAt,
    visualsGeneratedAt: prevData.visualsGeneratedAt,
    audioGeneratedAt: prevData.audioGeneratedAt,
    videoAssembledAt: prevData.videoAssembledAt,
    seoGeneratedAt: prevData.seoGeneratedAt,
    thumbnailGeneratedAt: new Date().toISOString()
  }
}];

// ============================================
// PIPELINE COMPLETE
// Final summary of the entire pipeline run
// ============================================

const upload = $input.first().json;
const prevData = $('Collect Thumbnail Results').first().json;

return [{
  json: {
    // Upload result
    videoId: upload.videoId || '',
    videoUrl: upload.videoUrl || '',
    uploadSuccess: upload.success || false,
    privacyStatus: upload.privacyStatus || 'private',
    thumbnailUploaded: upload.thumbnailUploaded || false,

    // SEO used
    youtubeTitle: prevData.youtubeTitle,
    youtubeCategory: prevData.youtubeCategory,
    tagCount: (prevData.youtubeTags || []).length,

    // Video info
    videoFilename: prevData.videoFilename,
    videoDuration: prevData.videoDuration,
    videoFileSizeMB: prevData.videoFileSizeMB,
    resolution: prevData.resolution,

    // Episode info
    episodeNumber: prevData.metadata?.episodeNumber || 1,
    seriesName: prevData.metadata?.seriesName || '',
    storyTitle: prevData.metadata?.storyTitle || '',

    // Pipeline timing
    pipelineStartedAt: prevData.pipelineStartedAt,
    scriptGeneratedAt: prevData.scriptGeneratedAt,
    scenesPlannedAt: prevData.scenesPlannedAt,
    visualsGeneratedAt: prevData.visualsGeneratedAt,
    audioGeneratedAt: prevData.audioGeneratedAt,
    videoAssembledAt: prevData.videoAssembledAt,
    seoGeneratedAt: prevData.seoGeneratedAt,
    thumbnailGeneratedAt: prevData.thumbnailGeneratedAt,
    uploadedAt: upload.uploadedAt || new Date().toISOString(),
    pipelineCompletedAt: new Date().toISOString()
  }
}];
